VALUES
  ('academic', 'physics', 900, '{"text": "What is the SI unit of speed?"}'::jsonb, '["m/s", "km/h", "m/s²", "km/s"]'::jsonb, 0, $$Speed = distance / time; SI units are metre and second.$$),
  ('academic', 'physics', 950, '{"text": "A body moving with uniform velocity has:"}'::jsonb, '["Zero acceleration", "Constant acceleration", "Variable acceleration", "Negative acceleration"]'::jsonb, 0, $$Uniform velocity means constant velocity; acceleration is rate of change of velocity.$$),
  ('academic', 'physics', 1000, '{"text": "What is the SI unit of force?"}'::jsonb, '["Newton", "Joule", "Watt", "Pascal"]'::jsonb, 0, $$Force = mass × acceleration; SI unit is kg·m/s² = Newton.$$),
  ('academic', 'physics', 1050, '{"text": "The value of acceleration due to gravity on Earth is approximately:"}'::jsonb, '["9.8 m/s²", "6.67 m/s²", "10.8 m/s²", "8.9 m/s²"]'::jsonb, 0, $$g on Earth surface is approximately 9.8 m/s².$$),
  ('academic', 'physics', 1100, '{"text": "The SI unit of work is:"}'::jsonb, '["Joule", "Newton", "Watt", "Pascal"]'::jsonb, 0, $$Work = Force × Displacement = N·m = Joule.$$),
  ('academic', 'chemistry', 900, '{"text": "What is the chemical symbol for gold?"}'::jsonb, '["Au", "Ag", "Fe", "Cu"]'::jsonb, 0, $$Au comes from Latin aurum.$$),
