  ('academic', 'chemistry', 1000, '{"text": "Which gas is most abundant in Earth''s atmosphere?"}'::jsonb, '["Nitrogen", "Oxygen", "Carbon dioxide", "Argon"]'::jsonb, 0, $$Nitrogen is about 78% of the atmosphere.$$),
